package plugins

import "fmt"

// DistributionChannel selects which implementation of the observability
// plugin an organization's generated packages carry. The channel is resolved
// per organization at generate time, so every distribution surface — the
// GitHub marketplace publish (and its 5-minute rollout sweep), the direct ZIP
// download, and the Codex install script — follows the same switch. Flipping
// an org's channel changes its generated bytes, which changes its plugin
// fingerprint, which makes the rollout workflow republish that org's
// marketplace within one tick; removing the override rolls back the same way.
type DistributionChannel string

const (
	// ChannelStable is the default: the bash-script hook senders every
	// organization receives today. The zero value is stable on purpose so
	// unenrolled orgs generate byte-identical output.
	ChannelStable DistributionChannel = ""
	// ChannelAlpha distributes the speakeasy-hooks binary variant: provider
	// configs invoke a small bootstrap shim that downloads the pinned binary
	// release on first use and forwards hook events to it.
	ChannelAlpha DistributionChannel = "alpha"
)

// orgDistributionChannels is the rollout switch. It is a code-level map on
// purpose: the gate rewrites fleet artifacts, so enrollment must be
// deterministic (a flapping runtime flag would republish and version-bump an
// org's plugins on every evaluation blip) and reviewable. Enroll an org by
// adding its organization id here; remove the entry to roll it back to the
// bash plugins on the next rollout tick.
var orgDistributionChannels = map[string]DistributionChannel{}

func channelForOrg(orgID string) DistributionChannel {
	return orgDistributionChannels[orgID]
}

// hooksBinaryPlatforms are the release archives the bootstrap shim can
// select. Windows is not served: hook plugins execute POSIX shell on every
// provider, which is the same constraint the bash channel has.
var hooksBinaryPlatforms = []string{"darwin_amd64", "darwin_arm64", "linux_amd64", "linux_arm64"}

// hooksBinaryPin identifies the hooks@<version> GitHub release the alpha
// plugin's shim downloads, plus the sha256 of each platform archive the shim
// verifies before installing. Bumping the pin changes every enrolled org's
// generated bytes, so a binary upgrade propagates through the same
// fingerprint-driven republish as any other plugin change.
type hooksBinaryPin struct {
	Version string
	// Checksums maps "<os>_<arch>" to the hex sha256 of
	// speakeasy-hooks_<os>_<arch>.zip from the pinned release.
	Checksums map[string]string
}

func (p hooksBinaryPin) validate() error {
	if p.Version == "" {
		return fmt.Errorf("hooks binary release is not pinned")
	}
	for _, platform := range hooksBinaryPlatforms {
		if p.Checksums[platform] == "" {
			return fmt.Errorf("hooks binary pin is missing a checksum for %s", platform)
		}
	}
	return nil
}

// currentHooksBinaryPin is empty until the first hooks@ release is published;
// while empty, alpha-channel generation fails loudly rather than emitting a
// shim that cannot verify what it downloads. Update Version and Checksums
// from the release's checksums.txt when rolling the fleet binary forward.
var currentHooksBinaryPin = hooksBinaryPin{
	Version:   "",
	Checksums: map[string]string{},
}
